<template><div class="conversations"><button v-for="c in items" :key="c.id" @click="navigate('/messages/'+c.id)"><div class="avatar"><img v-if="c.buyerAvatar" :src="c.buyerAvatar" alt=""/><span v-else>{{c.buyerName?.slice(0,1)||'客'}}</span></div><div class="conversation-copy"><strong>{{c.buyerName||'访客 '+c.id}} <em v-if="c.orderStatus">{{c.orderStatus}}</em></strong><p :class="{unread:c.unread}"><span v-if="c.unread">[未读] </span>{{c.lastMessage||'暂无消息'}}</p></div><div class="conversation-meta"><time>{{c.lastMessageAt}}</time><b v-if="c.unreadCount">{{c.unreadCount}}</b></div></button><p v-if="!items.length" class="empty">暂无买家咨询</p></div></template><script setup lang="ts">import{navigate}from'../router';defineProps<{items:any[]}>()</script>
